formulas.formula:
Here's a comprehensive formula sheet for CBSE Class 11 Economics - Human Capital Formation in India in JSON format:

[
  {
    "name": "Harris-Todaro Model",
    "formula": "Migration occurs when the urban wage is greater than or equal to the rural wage and the unemployment rate is positive.",
    "notes": "This model explains the migration of labor from rural to urban areas due to differences in wage rates and unemployment rates."
  },
  {
    "name": "Labor Force Participation Rate",
    "formula": "LFP = (L / P) x 100",
    "variables": {
      "LFP": "Labor Force Participation Rate",
      "L": "Labor Force (number of working-age individuals in the labor force)",
      "P": "Population"
    },
    "units": "%"
  },
  {
    "name": "Unemployment Rate",
    "formula": "UR = (U / L) x 100",
    "variables": {
      "UR": "Unemployment Rate",
      "U": "Unemployed individuals (number of individuals available for and seeking work but not employed)",
      "L": "Labor Force (number of working-age individuals in the labor force)"
    },
    "units": "%"
  },
  {
    "name": "Poverty Line",
    "formula": "Poverty Line = Minimum Expenditure required to meet Basic Needs",
    "notes": "The poverty line is the minimum expenditure required to meet the basic needs of an individual, typically defined as the cost of a basket of goods and services."
  },
  {
    "name": "Human Capital Formation",
    "formula": "HCF = (Education + Health) x (Labor Force)",
    "variables": {
      "HCF": "Human Capital Formation",
      "Education": "Education level or quality of the labor force",
      "Health": "Health status or quality of the labor force",
      "Labor Force": "Number of working-age individuals in the labor force"
    },
    "units": "Index"
  },
  {
    "name": "Returns to Education",
    "formula": "RTS = (Earnings per Year / Years of Education) x 100",
    "variables": {
      "RTS": "Returns to Education (Percentage increase in earnings per year due to education)",
      "Earnings per Year": "Annual earnings of an individual",
      "Years of Education": "Number of years of education"
    },
    "units": "%"
  },
  {
    "name": "Mincer Equation",
    "formula": "Incomes = β0 + β1 x Years of Education + β2 x Experience + ε",
    "variables": {
      "Incomes": "Annual earnings of an individual",
      "β0": "Intercept",
      "β1": "Coefficient of Years of Education",
      "β2": "Coefficient of Experience",
      "ε": "Error term"
    },
    "notes": "The Mincer equation estimates the relationship between earnings and years of education and experience."
  }
]

Note: The formulas and equations mentioned above are based on the commonly used ones in the context of Human Capital Formation in India and may not be exhaustive.
